<?php require_once __DIR__ . '/../config/database.php'; require_once __DIR__ . '/../includes/auth.php'; require_login();
$rows=$pdo->query('SELECT t.title,t.due_date,t.priority,t.status,l.full_name lead_name,u.full_name assignee FROM lead_tasks t LEFT JOIN leads l ON l.id=t.lead_id LEFT JOIN users u ON u.id=t.assigned_user_id ORDER BY t.due_date ASC')->fetchAll();
?><!doctype html><html><head><meta charset="utf-8"><title>Task Summary</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"></head><body class="p-4"><h3>Task Summary</h3><table class="table table-sm table-bordered"><thead><tr><th>Title</th><th>Lead</th><th>Assignee</th><th>Due</th><th>Priority</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?= htmlspecialchars($r['title']) ?></td><td><?= htmlspecialchars($r['lead_name']) ?></td><td><?= htmlspecialchars($r['assignee']) ?></td><td><?= htmlspecialchars($r['due_date']) ?></td><td><?= htmlspecialchars($r['priority']) ?></td><td><?= htmlspecialchars($r['status']) ?></td></tr><?php endforeach;?></tbody></table><script>window.print()</script></body></html>
